/**
 * Regenerates entrypoints/sdk/controlTypes.ts from controlSchemas Zod schemas.
 */
import { readFileSync, writeFileSync } from 'fs'
import { join } from 'path'

const root = join(import.meta.dirname, '..')
const schemaPath = join(root, 'entrypoints', 'sdk', 'controlSchemas.ts')
const outPath = join(root, 'entrypoints', 'sdk', 'controlTypes.ts')

const src = readFileSync(schemaPath, 'utf8')
const names = []
const re = /^export const (\w+Schema) = lazySchema/gm
let m
while ((m = re.exec(src))) names.push(m[1])

const lines = [
  '/** Auto-generated by scripts/emit-control-types.mjs — do not edit by hand. */',
  "import type { z } from 'zod/v4'",
  `import {\n  ${names.join(',\n  ')},\n} from './controlSchemas.js'`,
  '',
]

for (const schema of names) {
  const typeName = schema.replace(/Schema$/, '')
  lines.push(
    `export type ${typeName} = z.infer<ReturnType<typeof ${schema}>>`,
  )
}

lines.push('')
writeFileSync(outPath, lines.join('\n'), 'utf8')
console.error(`Wrote ${names.length} control types to ${outPath}`)
